# Build OpenCV with the same MinGW toolchain as Qt 6.11 (mingw1310_64).
#
#   powershell -ExecutionPolicy Bypass -File scripts/build_qt_mingw.ps1
#   powershell -ExecutionPolicy Bypass -File scripts/build_qt_mingw.ps1 -Rebuild

param(
    [string]$ExternalRoot = "",
    [string]$QtTools = "",
    [string]$OpenCvVersion = "4.13.0",
    [string]$BuildType = "Release",
    [switch]$Rebuild
)

$ErrorActionPreference = "Stop"

if (-not $ExternalRoot) {
    $ExternalRoot = Split-Path -Parent (Split-Path -Parent $MyInvocation.MyCommand.Path)
}

if (-not $QtTools) {
    if ($env:IQTA_TOOLS -and (Test-Path $env:IQTA_TOOLS)) {
        $QtTools = $env:IQTA_TOOLS
    } elseif (Test-Path "C:\Qt\Tools") {
        $QtTools = "C:\Qt\Tools"
    } else {
        $QtTools = "C:\Qt\Tools"
    }
}

$installDir = Join-Path $ExternalRoot "prebuilt"
$stampFile = Join-Path $installDir ".opencv_built"
$headerFile = Join-Path $installDir "include\opencv2\opencv.hpp"
$OpenCvModules = @("core", "imgproc", "imgcodecs")

function Get-OpenCvArtifact {
    param(
        [string]$Dir,
        [string]$Module,
        [string]$Extension
    )
    $pattern = "libopencv_${Module}*.$Extension"
    $candidates = Get-ChildItem $Dir -Filter $pattern -ErrorAction SilentlyContinue
    if (-not $candidates) {
        return $null
    }
    $versioned = $candidates | Where-Object { $_.BaseName -match "${Module}\d" } |
        Sort-Object LastWriteTime -Descending
    if ($versioned) {
        return $versioned | Select-Object -First 1
    }
    return $candidates | Sort-Object LastWriteTime -Descending | Select-Object -First 1
}

function Sync-OpenCvPrebuiltLayout {
    param([string]$Root)

    $mingwLib = Join-Path $Root "x64\mingw\lib"
    $mingwBin = Join-Path $Root "x64\mingw\bin"
    New-Item -ItemType Directory -Force -Path $mingwLib, $mingwBin | Out-Null

    $keptImport = @()
    $keptRuntime = @()
    foreach ($mod in $OpenCvModules) {
        $import = Get-OpenCvArtifact -Dir $mingwLib -Module $mod -Extension "dll.a"
        if (-not $import) {
            $installLib = Join-Path $Root "lib"
            $installBin = Join-Path $Root "bin"
            $import = Get-OpenCvArtifact -Dir $installLib -Module $mod -Extension "dll.a"
            if ($import) {
                Copy-Item $import.FullName $mingwLib -Force
                $import = Get-OpenCvArtifact -Dir $mingwLib -Module $mod -Extension "dll.a"
            }
            $runtime = Get-OpenCvArtifact -Dir $installBin -Module $mod -Extension "dll"
            if ($runtime) {
                Copy-Item $runtime.FullName $mingwBin -Force
            }
        }
        if (-not $import) {
            return $false
        }
        $keptImport += $import.Name

        $runtime = Get-OpenCvArtifact -Dir $mingwBin -Module $mod -Extension "dll"
        if ($runtime) {
            $keptRuntime += $runtime.Name
        }
    }

    Get-ChildItem $mingwLib -Filter "libopencv_*.dll.a" -ErrorAction SilentlyContinue |
        Where-Object { $keptImport -notcontains $_.Name } |
        Remove-Item -Force

    Get-ChildItem $mingwBin -Filter "libopencv_*.dll" -ErrorAction SilentlyContinue |
        Where-Object { $keptRuntime -notcontains $_.Name } |
        Remove-Item -Force

    $coreLib = (Get-OpenCvArtifact -Dir $mingwLib -Module "core" -Extension "dll.a").Name
    $imgprocLib = (Get-OpenCvArtifact -Dir $mingwLib -Module "imgproc" -Extension "dll.a").Name
    $imgcodecsLib = (Get-OpenCvArtifact -Dir $mingwLib -Module "imgcodecs" -Extension "dll.a").Name

    $qmakePwd = '$$PWD'
    $qmakePri = @"
# Generated by scripts/build_qt_mingw.ps1 - do not edit
OPENCV_QMAKE_GENERATED = true
OPENCV_LIB_CORE = $qmakePwd/x64/mingw/lib/$coreLib
OPENCV_LIB_IMGPROC = $qmakePwd/x64/mingw/lib/$imgprocLib
OPENCV_LIB_IMGCODECS = $qmakePwd/x64/mingw/lib/$imgcodecsLib
OPENCV_BINDIR = $qmakePwd/x64/mingw/bin
"@
    $priPath = Join-Path $Root "opencv_qmake.pri"
    $stampPath = Join-Path $Root ".opencv_built"
    [System.IO.File]::WriteAllText($priPath, $qmakePri)
    [System.IO.File]::WriteAllText($stampPath, (Get-Date -Format o))
    return $true
}

if (-not $Rebuild -and (Test-Path $stampFile) -and (Test-Path $headerFile)) {
    if (Sync-OpenCvPrebuiltLayout -Root $installDir) {
        Write-Host "OpenCV prebuilt up to date: $installDir"
        exit 0
    }
    Write-Host "OpenCV prebuilt incomplete - rebuilding..."
}

$mingwBin = Join-Path $QtTools "mingw1310_64\bin"
$cmake = Join-Path $QtTools "CMake_64\bin\cmake.exe"
$ninja = Join-Path $QtTools "Ninja\ninja.exe"

foreach ($tool in @($cmake, $ninja, (Join-Path $mingwBin "gcc.exe"))) {
    if (-not (Test-Path $tool)) {
        Write-Error "Missing tool: $tool"
    }
}

$env:Path = "$mingwBin;" + $env:Path

$sourcesRoot = Join-Path $ExternalRoot ".build\opencv-src"
$sourceDir = Join-Path $sourcesRoot "opencv-$OpenCvVersion"
$buildDir = Join-Path $ExternalRoot ".build\qt-mingw"

if (-not (Test-Path $sourceDir)) {
    New-Item -ItemType Directory -Force -Path $sourcesRoot | Out-Null
    $zip = Join-Path $sourcesRoot "opencv-$OpenCvVersion.zip"
    $url = "https://github.com/opencv/opencv/archive/refs/tags/$OpenCvVersion.zip"
    Write-Host "Downloading OpenCV $OpenCvVersion..."
    Invoke-WebRequest -Uri $url -OutFile $zip
    Expand-Archive -Path $zip -DestinationPath $sourcesRoot -Force
    Remove-Item $zip
}

Write-Host "OpenCV sources: $sourceDir"
Write-Host "Install to:     $installDir"
Write-Host "Toolchain:      $mingwBin"
Write-Host ""

if (Test-Path $buildDir) {
    Remove-Item -Recurse -Force $buildDir
}
New-Item -ItemType Directory -Force -Path $buildDir | Out-Null

$cmakeArgs = @(
    "-G", "Ninja",
    "-S", $sourceDir,
    "-B", $buildDir,
    "-DCMAKE_BUILD_TYPE=$BuildType",
    "-DCMAKE_INSTALL_PREFIX=$installDir",
    "-DCMAKE_C_COMPILER=$mingwBin\gcc.exe",
    "-DCMAKE_CXX_COMPILER=$mingwBin\g++.exe",
    "-DCMAKE_MAKE_PROGRAM=$ninja",
    "-DBUILD_SHARED_LIBS=ON",
    "-DBUILD_LIST=core,imgproc,imgcodecs",
    "-DBUILD_TESTS=OFF",
    "-DBUILD_PERF_TESTS=OFF",
    "-DBUILD_EXAMPLES=OFF",
    "-DBUILD_DOCS=OFF",
    "-DBUILD_opencv_apps=OFF",
    "-DBUILD_opencv_world=OFF",
    "-DWITH_TBB=OFF",
    "-DWITH_OPENMP=OFF",
    "-DWITH_IPP=OFF",
    "-DWITH_CUDA=OFF",
    "-DWITH_FFMPEG=OFF",
    "-DWITH_GTK=OFF",
    "-DWITH_QT=OFF",
    "-DWITH_OPENEXR=OFF",
    "-DWITH_WEBP=ON",
    "-DWITH_JPEG=ON",
    "-DWITH_PNG=ON",
    "-DWITH_TIFF=ON",
    "-DBUILD_ZLIB=ON",
    "-DBUILD_JPEG=ON",
    "-DBUILD_PNG=ON",
    "-DBUILD_TIFF=ON",
    "-DBUILD_WEBP=ON",
    "-DBUILD_OPENJPEG=ON"
)

Write-Host "Configuring..."
& $cmake @cmakeArgs
if ($LASTEXITCODE -ne 0) { exit $LASTEXITCODE }

Write-Host "Building (this takes several minutes)..."
& $cmake --build $buildDir --parallel
if ($LASTEXITCODE -ne 0) { exit $LASTEXITCODE }

Write-Host "Installing..."
& $cmake --install $buildDir
if ($LASTEXITCODE -ne 0) { exit $LASTEXITCODE }

$mingwOut = Join-Path $installDir "x64\mingw"
$mingwLib = Join-Path $mingwOut "lib"
$mingwBinOut = Join-Path $mingwOut "bin"
New-Item -ItemType Directory -Force -Path $mingwLib, $mingwBinOut | Out-Null

Get-ChildItem $mingwBinOut -Filter "*.dll" -ErrorAction SilentlyContinue | Remove-Item -Force
Get-ChildItem $mingwLib -Filter "libopencv_*.dll.a" -ErrorAction SilentlyContinue | Remove-Item -Force

$modules = @("core", "imgproc", "imgcodecs")
$libFrom = Join-Path $installDir "lib"
$binFrom = Join-Path $installDir "bin"

$copiedLibs = @()
foreach ($mod in $modules) {
    $importLib = Get-ChildItem $libFrom -Filter "libopencv_$mod*.dll.a" -ErrorAction SilentlyContinue |
        Sort-Object Name | Select-Object -First 1
    if (-not $importLib) {
        Write-Error "Missing import lib for opencv_$mod in $libFrom"
    }
    Copy-Item $importLib.FullName $mingwLib -Force
    $copiedLibs += $importLib.Name

    $runtimeDll = Get-ChildItem $binFrom -Filter "libopencv_$mod*.dll" -ErrorAction SilentlyContinue |
        Sort-Object Name | Select-Object -First 1
    if ($runtimeDll) {
        Copy-Item $runtimeDll.FullName $mingwBinOut -Force
    }
}

$includeFrom = Join-Path $installDir "include\opencv4\opencv2"
$includeTo = Join-Path $installDir "include\opencv2"
if (Test-Path $includeFrom) {
    if (Test-Path $includeTo) {
        Remove-Item $includeTo -Recurse -Force -ErrorAction SilentlyContinue
    }
    New-Item -ItemType Directory -Force -Path (Join-Path $installDir "include") | Out-Null
    cmd /c mklink /J "$includeTo" "$includeFrom" 2>$null
    if (-not (Test-Path $includeTo)) {
        Copy-Item $includeFrom $includeTo -Recurse -Force
    }
}

if (-not (Sync-OpenCvPrebuiltLayout -Root $installDir)) {
    Write-Error "Failed to finalize OpenCV prebuilt layout in $installDir"
}

Write-Host ""
Write-Host "Done. Qt-compatible OpenCV installed to:"
Write-Host "  $installDir"
Write-Host "  libs: $($copiedLibs -join ', ')"
Write-Host ""
